# A custom Iterator that counts up to a limit
class CounterIterator:
    def __init__(self, limit):
        self.limit = limit
        self.current = 0

    def __iter__(self):
        return self # Iterators must return themselves

    def __next__(self):
        if self.current < self.limit:
            val = self.current
            self.current += 1
            return val
        else:
            raise StopIteration # Signals the end of the loop

# Using it
for num in CounterIterator(3):
    print(num) # Prints 0, 1, 2
