import functools

# Level 1: The Factory (takes arguments)
def repeat(num_times):
    # Level 2: The Decorator (takes the function)
    def decorator_repeat(func):
        # Level 3: The Wrapper (executes the function)
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for _ in range(num_times):
                result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator_repeat

# The factory runs first, returning the decorator, which then wraps the function.
@repeat(num_times=3)
def greet(name):
    print(f"Hello, {name}!")

greet("Alice") # Prints Hello Alice 3 times
