# A standard recursive function that WILL hit the recursion limit
def factorial_standard(n):
    if n == 0: return 1
    # Not a tail call because we must multiply AFTER the function returns
    return n * factorial_standard(n - 1)

# A tail-recursive function (If Python supported TCO, this wouldn't overflow)
def factorial_tail(n, acc=1):
    if n == 0: return acc
    # The return IS the function call itself, nothing else.
    return factorial_tail(n - 1, acc * n)

import sys
print(sys.getrecursionlimit()) # Usually 1000

# TCO Workaround using Trampolining:
def trampoline(func, *args):
    result = func(*args)
    while callable(result):
        result = result()
    return result

def factorial_trampoline(n, acc=1):
    if n == 0: return acc
    # Return a lambda (a callable) instead of calling the function
    return lambda: factorial_trampoline(n - 1, acc * n)

# This will NOT overflow the stack!
print(trampoline(factorial_trampoline, 5000)) 
```

