// The actual C logic wrapped for Python
static PyObject* fast_hello(PyObject* self, PyObject* args) {
    const char* name;

    // Parse the Python arguments (expecting one string 's')
    if (!PyArg_ParseTuple(args, "s", &name)) {
        return NULL; // Raises TypeError automatically
    }

    // Create and return a new Python string object
    return PyUnicode_FromFormat("Hello from C, %s!", name);
}

// Method definition array
static PyMethodDef MyMethods[] = {
    {"fast_hello", fast_hello, METH_VARARGS, "Returns a fast greeting."},
    {NULL, NULL, 0, NULL} // Sentinel
};

// Module definition structure
static struct PyModuleDef mymodule = {
    PyModuleDef_HEAD_INIT, "mymodule", "A fast C extension.", -1, MyMethods
};

// Initialization function called by Python's import system
PyMODINIT_FUNC PyInit_mymodule(void) {
    return PyModule_Create(&mymodule);
