class Parent:
    def greet(self):
        return "Hello"

class Child(Parent):
    def greet(self):
        # We override the parent, but can still call it using super()
        return super().greet() + " from the child!"

# --- Overloading (Not Supported natively, simulated via decorators) ---
from functools import singledispatchmethod

class MathOperations:
    # We use singledispatchmethod to simulate overloading based on type!
    @singledispatchmethod
    def add(self, a, b):
        raise NotImplementedError("Unsupported type")

    @add.register(int)
    def _(self, a: int, b: int):
        return a + b

    @add.register(list)
    def _(self, a: list, b: list):
        return [x + y for x, y in zip(a, b)]

math = MathOperations()
print(math.add(5, 10))         # Calls the int version -> 15
print(math.add([1, 2], [3, 4])) # Calls the list version -> [4, 6]
