# Custom metaclass: runs at class DEFINITION time
class SingletonMeta(type):
    _instances = {}

    def __call__(cls, *args, **kwargs):
        # Intercepts instantiation to ensure only one object ever exists
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

# The moment Python reads this definition, the metaclass kicks in
class Database(metaclass=SingletonMeta):
    pass

assert Database() is Database()  # True — same instance
